import{_ as o,o as t,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"131. Ten Hour Break","description":"","frontmatter":{"title":"131. Ten Hour Break","eba":"Mental Health Services 2024-2028","topics":["hours","overtime","breaks"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/hours-of-work/131-ten-hour-break.md","filePath":"ebas/mental-health/health-professionals/hours-of-work/131-ten-hour-break.md"}'),s={name:"ebas/mental-health/health-professionals/hours-of-work/131-ten-hour-break.md"};function n(l,e,h,i,u,c){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_131-ten-hour-break" tabindex="-1">131. Ten Hour Break <a class="header-anchor" href="#_131-ten-hour-break" aria-label="Permalink to &quot;131. Ten Hour Break&quot;">​</a></h1><p><strong>131.1</strong> When overtime work, including recall work, is necessary it should be arranged so that Employees have at least ten consecutive hours off duty between all bodies of work.</p><p><strong>131.2</strong> An Employee who works so much overtime or recall between the cessation of the Employee&#39;s previous rostered ordinary hours and the commencement of the next succeeding rostered period of ordinary hours, that the Employee would not have at least ten consecutive hours off duty between the end of the overtime or recall and the commencement of the next rostered period of ordinary hours shall, subject to this clause, be released after completion of such overtime or recall worked until the Employee has had ten consecutive hours off duty without loss of pay for rostered ordinary hours occurring during such absence.</p><p><strong>131.3</strong> If, on the instructions of the Employer, an Employee resumes or continues work without having had ten successive hours off duty the Employee will be paid at the rate of double time until the Employee is released from duty for such rest period and the Employee will then be entitled to be absent until the Employee has had ten consecutive hours off duty without loss of pay for rostered hours occurring during such absence.</p><p><strong>131.4</strong> If an Employee resumes work of the Employee&#39;s own volition, overtime will be calculated in accordance with <a href="/eba/ebas/mental-health/health-professionals/hours-of-work/128-overtime.html">clause 128</a> - Overtime. An Employee who resumes work voluntarily will be entitled without loss of pay to attend to ablution and sustenance matters.</p>',5)])])}const f=o(s,[["render",n]]);export{m as __pageData,f as default};
